    public static void main(String args[]) {
        Scanner sc = new Scanner(System.in);
        long x = sc.nextLong();
        long n = 1;
        while (n <= x) {
            long sum = 0;
            while (n > 0) {
                sum += n % 10;
                n /= 10;
            }
            if (sum >= x) {
                System.out.println(x);
                return;
            }
            n++;
        }
        System.out.println(x);
    }
}


